namespace EvenNumberSum
{
    class Program
    {
        static void Main(string[] args)
        {
            // Main method to run the application
            while (true)
            {
                Console.WriteLine("Enter a positive integer or 'exit' to quit: ");
                string input = Console.ReadLine();

                if (input.ToLower() == "exit")
                {
                    Console.WriteLine("Exiting the application. Goodbye!");
                    break;
                }

                if (int.TryParse(input, out int number))
                {
                    if (number > 0)
                    {
                        int sum = CalculateEvenSum(number);
                        Console.WriteLine($"The sum of even numbers up to {number} is: {sum}");
                    }
                    else
                    {
                        Console.WriteLine("Please enter a positive integer.");
                    }
                }
                else
                {
                    Console.WriteLine("Invalid input. Please enter a positive integer.");
                }
            }
        }

        static int CalculateEvenSum(int number)
        {
            // Calculate the sum of all positive even numbers up to the entered number inclusively
            int sum = 0;
            for (int i = 2; i <= number; i += 2)
            {
                sum += i;
            }
            return sum;
        }
    }
}
```

