#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int n;
    cout << "Enter the length of the sequence: ";
    cin >> n;

    vector<int> nums(n);
    cout << "Enter the sequence of integers: ";
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }

    vector<int> dp(n, 1); // Initialize DP array with 1, as the smallest subsequence is the number itself

    // Compute the longest increasing subsequence
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (nums[i] > nums[j]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    // Find the maximum value in the DP array
    int maxLength = *max_element(dp.begin(), dp.end());

    cout << "Length of the longest increasing subsequence: " << maxLength << endl;

    return 0;
}
```

