```matlab
% 1D Heat Equation Solver using Finite Difference Method
% This script solves the 1D heat equation: u_t = alpha * u_xx
% with initial and boundary conditions.
% User can input rod length, time span, alpha (diffusion coefficient), and number of steps.

% Prompt user for parameters
rod_length = input('Enter the length of the rod (m): ');
T_final = input('Enter the final time (s): ');
alpha = input('Enter the diffusion coefficient (m^2/s): ');
n = input('Enter number of spatial steps: ');
m = input('Enter number of time steps: ');

% Initialize spatial and temporal steps
dx = rod_length / (n - 1);
dt = T_final / (m - 1);
x = linspace(0, rod_length, n);

% Initial condition: u(x,0) = 100 for 0 < x < 0.5, u(x,0) = 0 for 0.5 < x < 1
u = 100 * (x < 0.5);

% Boundary conditions: u(0,t) = 0, u(L,t) = 0
u(1) = 0; % Left end
u(end) = 0; % Right end

% Time-stepping loop
for t = 1:m
    u_new = u; % Copy current solution to a new array
    for i = 2:n-1
        u_new(i) = u(i) + alpha * dt / dx^2 * (u(i+1) - 2*u(i) + u(i-1));
    end
    u = u_new; % Update solution for next time step
    % Plot the solution
    plot(x, u, 'DisplayName', sprintf('t = %.2fs', t*dt));
    hold on;
end
xlabel('Position (x)');
ylabel('Temperature (u)');
legend show;
title('1D Heat Equation Solution');
hold off;

